### RxDB Live Updates with RxJS Observables and React Hooks (TypeScript)

Source: https://github.com/pubkey/rxdb/blob/master/docs-src/docs/articles/react-indexeddb.md

Shows how to create a reactive component in React that subscribes to live data updates from an RxDB collection using RxJS Observables. The UI automatically updates when the data changes.

```typescript
import { useState, useEffect } from 'react';

function HeroList({ collection }) {
  const [heroes, setHeroes] = useState([]);

  useEffect(() => {
    // create an observable query
    const query = collection.find();
    const subscription = query.$.subscribe(newHeroes => {
      setHeroes(newHeroes);
    });
    return () => subscription.unsubscribe();
  }, [collection]);

  return (
    <div>
      <h2>Hero List</h2>
      <ul>
        {heroes.map(hero => (
          <li key={hero.id}>
            <strong>{hero.name}</strong> - {hero.power}
          </li>
        ))}
      </ul>
    </div>
  );
}
```

